import React, { useState, useEffect, useRef } from 'react';

const Skills = () => {
  const [hoveredSkill, setHoveredSkill] = useState(null);
  const containerRef = useRef(null);

  const frontendSkills = [
    { name: 'React', icon: '⚛️', desc: 'UI Library' },
    { name: 'Next.js', icon: '▲', desc: 'React Framework' },
    { name: 'TypeScript', icon: '📘', desc: 'Typed JS' },
    { name: 'JavaScript', icon: '⚡', desc: 'Programming' },
    { name: 'HTML5', icon: '🌐', desc: 'Markup' },
    { name: 'CSS3', icon: '🎨', desc: 'Styling' },
    { name: 'Tailwind CSS', icon: '💨', desc: 'Utility CSS' },
    { name: 'Redux', icon: '🔄', desc: 'State Mgmt' },
    { name: 'Framer Motion', icon: '🎬', desc: 'Animations' }
  ];

  const backendSkills = [
    { name: 'Node.js', icon: '🟢', desc: 'Runtime' },
    { name: 'Express.js', icon: '🚀', desc: 'Framework' },
    { name: 'MongoDB', icon: '🍃', desc: 'NoSQL DB' },
    { name: 'JWT', icon: '🔐', desc: 'Auth' },
    { name: 'REST API', icon: '🔗', desc: 'APIs' },
    { name: 'Socket.io', icon: '📡', desc: 'Real-time' },
    { name: 'Mongoose', icon: '📦', desc: 'ODM' },
    { name: 'Cloudinary', icon: '☁️', desc: 'Cloud Storage' }
  ];

  const allSkills = [...frontendSkills, ...backendSkills];

  // Generate random positions with circular pattern
  const [positions, setPositions] = useState([]);

  useEffect(() => {
    const centerX = 50;
    const centerY = 50;
    const radius = 30;
    const count = allSkills.length;

    const newPositions = allSkills.map((_, index) => {
      // 70% chance to be in circular orbit, 30% random
      const isCircular = Math.random() < 0.7;

      if (isCircular) {
        const angle = (index / count) * 2 * Math.PI + Math.random() * 0.5;
        const r = radius + (Math.random() - 0.5) * 15;
        return {
          top: centerY + r * Math.sin(angle) + (Math.random() - 0.5) * 8,
          left: centerX + r * Math.cos(angle) + (Math.random() - 0.5) * 8,
          duration: 6 + Math.random() * 4,
          delay: Math.random() * 3,
          size: 55 + Math.random() * 25,
          angle: angle,
          orbitSpeed: 0.3 + Math.random() * 0.3,
          orbitRadius: r,
          isCircular: true
        };
      } else {
        return {
          top: 5 + Math.random() * 85,
          left: 5 + Math.random() * 85,
          duration: 5 + Math.random() * 5,
          delay: Math.random() * 3,
          size: 55 + Math.random() * 25,
          isCircular: false
        };
      }
    });
    setPositions(newPositions);
  }, []);

  // Orbit animation
  useEffect(() => {
    if (positions.length === 0) return;

    let animationFrame;
    let startTime = Date.now();

    const animateOrbit = () => {
      const elapsed = (Date.now() - startTime) / 1000;

      const updatedPositions = positions.map((pos, index) => {
        if (pos.isCircular) {
          const newAngle = pos.angle + elapsed * pos.orbitSpeed * 0.1;
          const centerX = 50;
          const centerY = 50;
          return {
            ...pos,
            currentTop: centerY + pos.orbitRadius * Math.sin(newAngle) + (Math.random() - 0.5) * 4,
            currentLeft: centerX + pos.orbitRadius * Math.cos(newAngle) + (Math.random() - 0.5) * 4
          };
        }
        return pos;
      });

      // Update positions in state
      setPositions(updatedPositions);
      animationFrame = requestAnimationFrame(animateOrbit);
    };

    animateOrbit();

    return () => cancelAnimationFrame(animationFrame);
  }, [positions.length]);

  return (
    <section id="skills" className="relative z-10 py-16 px-6 overflow-hidden">
      <div 
        ref={containerRef}
        className="relative min-h-[600px] w-full"
        style={{
          background: 'radial-gradient(ellipse at center, rgba(139,92,246,0.03) 0%, transparent 70%)'
        }}
      >
        {allSkills.map((skill, index) => {
          const pos = positions[index] || { 
            top: 50, 
            left: 50, 
            duration: 5, 
            delay: 0, 
            size: 65,
            currentTop: 50,
            currentLeft: 50
          };

          const top = pos.currentTop !== undefined ? pos.currentTop : pos.top;
          const left = pos.currentLeft !== undefined ? pos.currentLeft : pos.left;

          return (
            <div
              key={index}
              onMouseEnter={() => setHoveredSkill(skill.name)}
              onMouseLeave={() => setHoveredSkill(null)}
              className="absolute cursor-pointer transition-all duration-300"
              style={{
                top: `${top}%`,
                left: `${left}%`,
                transform: 'translate(-50%, -50%)',
                animation: pos.isCircular ? 'none' : `floatStar ${pos.duration}s ease-in-out infinite`,
                animationDelay: pos.isCircular ? '0s' : `${pos.delay}s`,
                zIndex: hoveredSkill === skill.name ? 50 : 10,
                opacity: hoveredSkill === skill.name ? 1 : 0.7
              }}
            >
              <div 
                className="flex flex-col items-center justify-center rounded-full bg-[#1a1f2e]/40 backdrop-blur-sm border border-white/5 hover:border-purple-500/40 transition-all duration-500"
                style={{
                  width: hoveredSkill === skill.name ? `${pos.size + 30}px` : `${pos.size}px`,
                  height: hoveredSkill === skill.name ? `${pos.size + 30}px` : `${pos.size}px`,
                  boxShadow: hoveredSkill === skill.name ? '0 0 60px rgba(139,92,246,0.2)' : 'none',
                  transform: hoveredSkill === skill.name ? 'scale(1.2)' : 'scale(1)',
                  background: hoveredSkill === skill.name ? 'rgba(26,31,46,0.8)' : 'rgba(26,31,46,0.3)'
                }}
              >
                <span 
                  className="transition-all duration-500"
                  style={{ 
                    fontSize: hoveredSkill === skill.name ? '28px' : '20px',
                    filter: hoveredSkill === skill.name ? 'brightness(1.3)' : 'brightness(0.8)'
                  }}
                >
                  {skill.icon}
                </span>

                {hoveredSkill === skill.name && (
                  <>
                    <span className="text-[10px] font-semibold text-white mt-1 animate-fadeIn">
                      {skill.name}
                    </span>
                    <span className="text-[8px] text-purple-300 animate-fadeIn">
                      {skill.desc}
                    </span>
                  </>
                )}
              </div>
            </div>
          );
        })}

        {/* Glowing Center */}
        <div 
          className="absolute rounded-full"
          style={{
            top: '50%',
            left: '50%',
            transform: 'translate(-50%, -50%)',
            width: '350px',
            height: '350px',
            background: 'radial-gradient(circle, rgba(139,92,246,0.08) 0%, transparent 70%)',
            animation: 'moonPulse 6s ease-in-out infinite',
            pointerEvents: 'none',
            zIndex: 0
          }}
        />

        {/* Inner Glow */}
        <div 
          className="absolute rounded-full"
          style={{
            top: '50%',
            left: '50%',
            transform: 'translate(-50%, -50%)',
            width: '150px',
            height: '150px',
            background: 'radial-gradient(circle, rgba(139,92,246,0.04) 0%, transparent 70%)',
            animation: 'moonPulse 4s ease-in-out infinite reverse',
            pointerEvents: 'none',
            zIndex: 0
          }}
        />
      </div>

      {/* Stats */}
      <div className="max-w-6xl mx-auto">
        <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mt-8 glass-card rounded-2xl p-6">
          <div className="text-center">
            <div className="text-2xl font-bold text-white">20+</div>
            <div className="text-[10px] text-gray-500">Projects Completed</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">15+</div>
            <div className="text-[10px] text-gray-500">Happy Clients</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">2+</div>
            <div className="text-[10px] text-gray-500">Years Experience</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">2000+</div>
            <div className="text-[10px] text-gray-500">Cups of Coffee</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">5</div>
            <div className="text-[10px] text-gray-500">Technologies Mastered</div>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes floatStar {
          0%, 100% { 
            transform: translate(-50%, -50%) translateY(0px); 
          }
          50% { 
            transform: translate(-50%, -50%) translateY(-15px); 
          }
        }

        @keyframes moonPulse {
          0%, 100% { 
            transform: translate(-50%, -50%) scale(1);
            opacity: 0.5;
          }
          50% { 
            transform: translate(-50%, -50%) scale(1.2);
            opacity: 1;
          }
        }

        @keyframes fadeIn {
          from {
            opacity: 0;
            transform: scale(0.8);
          }
          to {
            opacity: 1;
            transform: scale(1);
          }
        }

        .animate-fadeIn {
          animation: fadeIn 0.25s ease-out forwards;
        }
      `}</style>
    </section>
  );
};

export default Skills;
